// Timeline:
// t=0   userId changes to 1 → fetch('/api/users/1') starts (request A)
// t=50  userId changes to 2 → fetch('/api/users/2') starts (request B)
// t=80  request B resolves → setUser(user2)  ✓ correct
// t=200 request A resolves → setUser(user1)  ✗ overwrites correct data!

// The UI now shows user1's data even though userId is 2.
// This is the race condition.

function UserProfile({ userId }) {
  const [user, setUser] = useState(null);

  useEffect(() => {
    const controller = new AbortController();

    fetch(`/api/users/${userId}`, { signal: controller.signal })
      .then(res => res.json())
      .then(data => setUser(data))
      .catch(err => {
        if (err.name !== 'AbortError') throw err; // ignore cancellations
      });

    return () => controller.abort(); // cancel on unmount or dep change
  }, [userId]);

  if (!user) return <p>Loading...</p>;
  return <p>{user.name}</p>;
}

useEffect(() => {
  let ignore = false;

  fetch(`/api/users/${userId}`)
    .then(res => res.json())
    .then(data => {
      if (!ignore) setUser(data); // skip if already cleaned up
    });

  return () => {
    ignore = true; // stale response will be discarded
  };
}, [userId]);

function UserProfile({ userId }) {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const controller = new AbortController();
    setLoading(true);
    setError(null);

    fetch(`/api/users/${userId}`, { signal: controller.signal })
      .then(res => {
        if (!res.ok) throw new Error(`HTTP ${res.status}`);
        return res.json();
      })
      .then(data => {
        setUser(data);
        setLoading(false);
      })
      .catch(err => {
        if (err.name === 'AbortError') return;
        setError(err.message);
        setLoading(false);
      });

    return () => controller.abort();
  }, [userId]);

  if (loading) return <p>Loading...</p>;
  if (error) return <p>Error: {error}</p>;
  return <p>{user.name}</p>;
}

useEffect(() => {
  const controller = new AbortController();
  const { signal } = controller;

  async function run() {
    try {
      const orgRes = await fetch(`/api/orgs/${orgId}`, { signal });
      const org = await orgRes.json();

      const repoRes = await fetch(`/api/orgs/${org.id}/repos`, { signal });
      const repos = await repoRes.json();

      setRepos(repos);
    } catch (err) {
      if (err.name !== 'AbortError') setError(err.message);
    }
  }

  run();
  return () => controller.abort(); // aborts whichever fetch is in-flight
}, [orgId]);

function useFetch(url) {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    if (!url) return;
    const controller = new AbortController();
    setLoading(true);
    setError(null);

    fetch(url, { signal: controller.signal })
      .then(res => {
        if (!res.ok) throw new Error(`HTTP ${res.status}`);
        return res.json();
      })
      .then(data => { setData(data); setLoading(false); })
      .catch(err => {
        if (err.name === 'AbortError') return;
        setError(err.message);
        setLoading(false);
      });

    return () => controller.abort();
  }, [url]);

  return { data, loading, error };
}

// Usage — no race-condition boilerplate in the component:
function UserProfile({ userId }) {
  const { data: user, loading, error } = useFetch(`/api/users/${userId}`);
  if (loading) return <p>Loading...</p>;
  if (error) return <p>Error: {error}</p>;
  return <p>{user.name}</p>;
}

// ✗ Wrong: effect callback is async
useEffect(async () => {
  const data = await fetch('/api/data').then(r => r.json());
  setData(data);
  // return value is a Promise, not a cleanup function
  // React warns: 'An effect function must not return anything besides a function'
}, []);

// ✓ Correct: async logic inside a named inner function
useEffect(() => {
  async function load() {
    const data = await fetch('/api/data').then(r => r.json());
    setData(data);
  }
  load();
  // cleanup can still be returned synchronously
}, []);

// With Strict Mode (development only):
// mount  → fetch('/api/users/1') starts
// cleanup → controller.abort()  ← correct cleanup
// remount → fetch('/api/users/1') starts again ← fresh request

// Without cleanup (broken):
// mount  → fetch starts
// cleanup → nothing
// remount → fetch starts AGAIN, now two requests in-flight for same userId
// React warns about calling setState on an unmounted component

function SearchResults({ query }) {
  const [results, setResults] = useState([]);

  useEffect(() => {
    if (!query) { setResults([]); return; }

    const controller = new AbortController();

    // Delay the fetch by 300ms after the last keystroke
    const timerId = setTimeout(() => {
      fetch(`/api/search?q=${encodeURIComponent(query)}`, {
        signal: controller.signal,
      })
        .then(res => res.json())
        .then(setResults)
        .catch(err => {
          if (err.name !== 'AbortError') console.error(err);
        });
    }, 300);

    return () => {
      clearTimeout(timerId);   // cancel the pending delay
      controller.abort();      // cancel any in-flight request
    };
  }, [query]);

  return <ul>{results.map(r => <li key={r.id}>{r.title}</li>)}</ul>;
}

function ItemList({ filter }) {
  const [page, setPage] = useState(1);
  const [items, setItems] = useState([]);

  // Reset to page 1 whenever the filter changes
  useEffect(() => {
    setPage(1);
  }, [filter]);

  useEffect(() => {
    const controller = new AbortController();

    fetch(`/api/items?filter=${filter}&page=${page}`, {
      signal: controller.signal,
    })
      .then(res => res.json())
      .then(setItems)
      .catch(err => {
        if (err.name !== 'AbortError') console.error(err);
      });

    return () => controller.abort();
  }, [filter, page]); // both are dependencies

  return (
    <>
      <ul>{items.map(i => <li key={i.id}>{i.name}</li>)}</ul>
      <button onClick={() => setPage(p => p + 1)}>Next</button>
    </>
  );
}

